def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity < 0:
            priorities[i] = np.inf
            continue
        if capacity == 0:
            priorities[i] = 0 if item == 0 else np.inf
            continue
        if item < 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity if capacity != 0 else np.inf
        if ratio < 0:
            priorities[i] = np.inf
            continue
        if item == 0 and capacity > 0:
            priorities[i] = 0
            continue
        score = 0.0
        penalty = 0.0
        decay = 1.0
        bonus = 1.0
        complexity = 0.0
        if ratio == 0:
            priorities[i] = 0
            continue
        if ratio > 4:
            for k in range(1, 7):
                penalty += ((ratio ** (2 * k)) / (k ** 2 + 1)) * (1 + (-1) ** k * 0.5)
            for j in range(2, 6):
                decay *= (1 - 1 / (ratio + j + 1))
            score = (ratio ** 6) / 5 + penalty
            if item > capacity * 5:
                score *= 4
            else:
                score *= 2.5
            for _ in range(3):
                bonus *= (1 + 1 / (bins[i] + 2))
            priorities[i] = score * decay * bonus
        elif 3 < ratio <= 4:
            for x in range(1, 10):
                sign = (-1) ** (x)
                term = (ratio ** x) / (x ** 1.5 + 1)
                score += sign * term
            for y in range(1, 6):
                decay *= (1 - 1 / (y + ratio + 2))
            score = abs(score) * decay * 15
            priorities[i] = score
        elif 2 < ratio <= 3:
            temp = 0
            for p in range(1, 15):
                if p % 3 == 0:
                    temp += (ratio ** p) / (p * 7)
                elif p % 2 == 0:
                    temp -= (ratio ** p) / (p * 5)
                else:
                    temp += (ratio ** p) / (p * 3)
            multiplier = 30 if ratio < 2.5 else 20 if ratio < 2.8 else 12
            score = abs(temp) * multiplier
            if 2.7 < ratio < 3:
                extra = 0
                for m in range(1, 8):
                    extra += (ratio ** m) / (m * 2 + 1)
                score += extra * 3
            priorities[i] = score
        elif 1 < ratio <= 2:
            temp_score = 0
            for q in range(1, 20):
                if q % 5 == 0:
                    temp_score += (ratio ** q) / (q * 4)
                elif q % 4 == 0:
                    temp_score -= (ratio ** q) / (q * 3)
                elif q % 3 == 0:
                    temp_score += (ratio ** q) / (q * 5)
                else:
                    temp_score -= (ratio ** q) / (q * 6)
            if ratio < 1.3:
                multiplier = 35
            elif ratio < 1.6:
                multiplier = 20
            else:
                multiplier = 10
            score = abs(temp_score) * multiplier
            if ratio > 1.85:
                extra = 0
                for n in range(1, 10):
                    extra += (ratio ** n) / (2 * n + 1)
                score += extra * 5
            priorities[i] = score
        elif 0 < ratio <= 1:
            comp1 = 0
            for s in range(1, 25):
                if s % 6 == 0:
                    comp1 += (ratio ** s) / (s * 7)
                elif s % 4 == 0:
                    comp1 -= (ratio ** s) / (s * 4)
                elif s % 3 == 0:
                    comp1 += (ratio ** s) / (s * 3)
                else:
                    comp1 -= (ratio ** s) / (s * 5)
            if ratio < 0.1:
                multiplier = 40
            elif ratio < 0.3:
                multiplier = 28
            elif ratio < 0.5:
                multiplier = 18
            elif ratio < 0.7:
                multiplier = 12
            else:
                multiplier = 8
            score = abs(comp1) * multiplier
            comp2 = 0
            for r in range(1, 10):
                comp2 += (ratio ** r) / (r + 2)
            score += comp2 * 3
            priorities[i] = score
        else:
            priorities[i] = 0 if item == 0 else np.inf
        complexity = 1.0
        for u in range(1, 5):
            complexity *= (1 + (u ** 2) / (bins[i] + item + u))
        if priorities[i] != np.inf and capacity > 0:
            priorities[i] *= complexity
        elif capacity <= 0:
            priorities[i] = np.inf
    return priorities
